syntax = "proto3";
package sales;

// Protobuf message = DDIC structure + data element
message SalesOrderRequest {
  string customer_id = 1;         // LIKE KUNNR (10 chars)
  int32 max_results = 2;          // LIKE SY-TABIX
  string status_filter = 3;       // LIKE VBUK-GBSTK
  // Field numbers 4-5 reserved for future use
  reserved 4, 5;
}

message SalesOrder {
  string id              = 1;     // LIKE VBELN (10 chars)
  string customer_name   = 2;     // LIKE KUNNR-KUNNR -> NAME1
  double total_amount    = 3;     // LIKE NETWR
  string currency        = 4;     // LIKE WAERS
  repeated LineItem items = 5;    // LIKE internal table
}

message LineItem {
  string item_id   = 1;           // LIKE POSNR (6 chars)
  string product   = 2;           // LIKE MATNR (18 chars)
  int32 quantity   = 3;           // LIKE MENGE_D
  double unit_price = 4;          // LIKE NETPR
}

// Service = function group / function module set
service SalesOrderService {
  // Unary RPC = synchronous RFC call
  rpc GetSalesOrders(SalesOrderRequest) returns (SalesOrder);
  // Server-streaming RPC = RFC table response
  rpc ListAllSalesOrders(SalesOrderRequest) returns (stream SalesOrder);
}
